var exclusiveAccordion=function($scope,$){var accordionTitle=$scope.find('.exad-accordion-title');accordionTitle.each(function(){if($(this).hasClass('active-default')){$(this).addClass('active');$(this).next('.exad-accordion-content').slideDown();}});accordionTitle.unbind('click');accordionTitle.click(function(e){e.preventDefault();if($(this).hasClass('active')){$(this).removeClass('active');$(this).next().slideUp(400);}else{$(this).parent().parent().find('.exad-accordion-title').removeClass('active');$(this).parent().parent().find('.exad-accordion-content').slideUp(400);$(this).toggleClass('active');$(this).next().slideToggle(400);}});}